int maximum( int a, int b, int c){
	int k;
	if( b >= a )
		k = b;
	else 
		k = a;

	if( c >= k )
		return(c);
	else
		return(k);
}

// Helper to run the kernel logic for a specific block (bx)
void run_kernel1_block(int bx, int* reference_d, int* input_itemsets_d, 
                       int cols, int penalty, int blk, int block_width, 
                       int worksize, int offset_r, int offset_c) {

    int tx;
    // We will iterate tx from 0 to BLOCK_SIZE-1 sequentially within this thread
    // to simulate the group behavior without needing explicit barriers between threads.
    // This converts the parallel group execution into a sequential loop per block.

    int base = offset_r * cols + offset_c;
    int b_index_x = bx;
    int b_index_y = blk - 1 - bx;

    int index_nw = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
    int index_w = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + cols;
    int index_n = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + 1;
    int index_base = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + cols + 1;

    // Local arrays for this block
    int input_itemsets_l[(BLOCK_SIZE+1)*(BLOCK_SIZE+1)];
    int reference_l[BLOCK_SIZE*BLOCK_SIZE];

    // Initialize boundary conditions (simulating the work of all threads in the group)
    // Thread 0 work
    input_itemsets_l[0 * (BLOCK_SIZE+1) + 0] = input_itemsets_d[index_nw];

    // All threads work for REF
    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx_local = 0; tx_local < BLOCK_SIZE; tx_local++) {
             // Original: REF(ty, tx) = reference_d[index + cols * ty]; 
             // Note: In original, index depends on tx. 
             // index = ... + tx + (cols+1). 
             // So reference_d[index + cols*ty] = reference_d[base + ... + tx + cols+1 + cols*ty]
             // This means each column tx loads a different column from reference_d.
             int idx = index_base + tx_local + cols * ty;
             reference_l[ty * BLOCK_SIZE + tx_local] = reference_d[idx];
        }
    }

    // Thread tx work for SCORE boundaries
    for (int tx_local = 0; tx_local < BLOCK_SIZE; tx_local++) {
        input_itemsets_l[(tx_local + 1) * (BLOCK_SIZE+1) + 0] = input_itemsets_d[index_w + cols * tx_local];
        input_itemsets_l[0 * (BLOCK_SIZE+1) + (tx_local + 1)] = input_itemsets_d[index_n + tx_local];
    }

    // Main DP loops
    // Original: for m=0..BLOCK_SIZE-1, if m>=tx, compute. Barrier.
    // Since we are sequentializing the group, we just compute all valid (tx, m) pairs.
    // The dependency is: SCORE(t_index_y, t_index_x) depends on previous row/col.
    // t_index_y = m - tx + 1, t_index_x = tx + 1.
    // As m increases, we fill diagonals.

    for (int m = 0; m < BLOCK_SIZE; m++) {
        for (int tx_local = 0; tx_local <= m; tx_local++) {
            int t_index_x = tx_local + 1;
            int t_index_y = m - tx_local + 1;

            int val_diag = input_itemsets_l[(t_index_y-1)*(BLOCK_SIZE+1) + (t_index_x-1)] + 
                           reference_l[(t_index_y-1)*BLOCK_SIZE + (t_index_x-1)];
            int val_left = input_itemsets_l[t_index_y*(BLOCK_SIZE+1) + (t_index_x-1)] - penalty;
            int val_up   = input_itemsets_l[(t_index_y-1)*(BLOCK_SIZE+1) + t_index_x] - penalty;

            input_itemsets_l[t_index_y*(BLOCK_SIZE+1) + t_index_x] = maximum(val_diag, val_left, val_up);
        }
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        for (int tx_local = 0; tx_local <= m; tx_local++) {
            int t_index_x = tx_local + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx_local;

            int val_diag = input_itemsets_l[(t_index_y-1)*(BLOCK_SIZE+1) + (t_index_x-1)] + 
                           reference_l[(t_index_y-1)*BLOCK_SIZE + (t_index_x-1)];
            int val_left = input_itemsets_l[t_index_y*(BLOCK_SIZE+1) + (t_index_x-1)] - penalty;
            int val_up   = input_itemsets_l[(t_index_y-1)*(BLOCK_SIZE+1) + t_index_x] - penalty;

            input_itemsets_l[t_index_y*(BLOCK_SIZE+1) + t_index_x] = maximum(val_diag, val_left, val_up);
        }
    }

    // Write back
    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx_local = 0; tx_local < BLOCK_SIZE; tx_local++) {
            int idx = index_base + tx_local + cols * ty;
            input_itemsets_d[idx] = input_itemsets_l[(ty+1)*(BLOCK_SIZE+1) + (tx_local+1)];
        }
    }
}

void run_kernel2_block(int bx, int* reference_d, int* input_itemsets_d, 
                       int cols, int penalty, int blk, int block_width, 
                       int worksize, int offset_r, int offset_c) {

    int base = offset_r * cols + offset_c;
    int b_index_x = bx + block_width - blk;
    int b_index_y = block_width - bx - 1;

    int index_nw = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
    int index_w = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + cols;
    int index_n = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + 1;
    int index_base = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + cols + 1;

    int input_itemsets_l[(BLOCK_SIZE+1)*(BLOCK_SIZE+1)];
    int reference_l[BLOCK_SIZE*BLOCK_SIZE];

    // Init
    input_itemsets_l[0] = input_itemsets_d[index_nw];

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx_local = 0; tx_local < BLOCK_SIZE; tx_local++) {
            int idx = index_base + tx_local + cols * ty;
            reference_l[ty * BLOCK_SIZE + tx_local] = reference_d[idx];
        }
    }

    for (int tx_local = 0; tx_local < BLOCK_SIZE; tx_local++) {
        input_itemsets_l[(tx_local + 1) * (BLOCK_SIZE+1) + 0] = input_itemsets_d[index_w + cols * tx_local];
        input_itemsets_l[0 * (BLOCK_SIZE+1) + (tx_local + 1)] = input_itemsets_d[index_n + tx_local];
    }

    // Loops
    for (int m = 0; m < BLOCK_SIZE; m++) {
        for (int tx_local = 0; tx_local <= m; tx_local++) {
            int t_index_x = tx_local + 1;
            int t_index_y = m - tx_local + 1;

            int val_diag = input_itemsets_l[(t_index_y-1)*(BLOCK_SIZE+1) + (t_index_x-1)] + 
                           reference_l[(t_index_y-1)*BLOCK_SIZE + (t_index_x-1)];
            int val_left = input_itemsets_l[t_index_y*(BLOCK_SIZE+1) + (t_index_x-1)] - penalty;
            int val_up   = input_itemsets_l[(t_index_y-1)*(BLOCK_SIZE+1) + t_index_x] - penalty;

            input_itemsets_l[t_index_y*(BLOCK_SIZE+1) + t_index_x] = maximum(val_diag, val_left, val_up);
        }
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        for (int tx_local = 0; tx_local <= m; tx_local++) {
            int t_index_x = tx_local + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx_local;

            int val_diag = input_itemsets_l[(t_index_y-1)*(BLOCK_SIZE+1) + (t_index_x-1)] + 
                           reference_l[(t_index_y-1)*BLOCK_SIZE + (t_index_x-1)];
            int val_left = input_itemsets_l[t_index_y*(BLOCK_SIZE+1) + (t_index_x-1)] - penalty;
            int val_up   = input_itemsets_l[(t_index_y-1)*(BLOCK_SIZE+1) + t_index_x] - penalty;

            input_itemsets_l[t_index_y*(BLOCK_SIZE+1) + t_index_x] = maximum(val_diag, val_left, val_up);
        }
    }

    // Write back (Note: original kernel2 writes with ty*cols + tx pattern? 
    // Original: input_itemsets_d[index + ty * cols] = SCORE((ty+1), (tx+1));
    // Wait, original kernel2 write loop:
    // for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
    //   input_itemsets_d[index + ty * cols] = SCORE((ty+1), (tx+1));
    // This looks like it only writes one column per thread? 
    // In kernel2, tx is fixed for the thread. The loop over ty writes SCORE(ty+1, tx+1) to index + ty*cols.
    // index = base + ... + tx + cols + 1.
    // So it writes to column tx.
    // We need to replicate this for all tx.

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx_local = 0; tx_local < BLOCK_SIZE; tx_local++) {
            int idx = index_base + tx_local + ty * cols;
            input_itemsets_d[idx] = input_itemsets_l[(ty+1)*(BLOCK_SIZE+1) + (tx_local+1)];
        }
    }
}

void nw_kernel1(int* reference_d, int* input_itemsets_d, int* output_itemsets_d, 
                int cols, int penalty, int blk, int block_width, int worksize, 
                int offset_r, int offset_c) {
    int num_blocks = blk;
    #pragma omp parallel for
    for (int bx = 0; bx < num_blocks; bx++) {
        run_kernel1_block(bx, reference_d, input_itemsets_d, cols, penalty, blk, block_width, worksize, offset_r, offset_c);
    }
}

void nw_kernel2(int* reference_d, int* input_itemsets_d, int* output_itemsets_d, 
                int cols, int penalty, int blk, int block_width, int worksize, 
                int offset_r, int offset_c) {
    int num_blocks = blk;
    #pragma omp parallel for
    for (int bx = 0; bx < num_blocks; bx++) {
        run_kernel2_block(bx, reference_d, input_itemsets_d, cols, penalty, blk, block_width, worksize, offset_r, offset_c);
    }
}

